/// NOT a part of public API. Pretend to get a mutable reference from a shared reference. For
/// internal/generated compile-time checks only.
#[doc(hidden)]
pub const fn shared_to_mut<T>(_: &T) -> &mut T {
    unreachable!()
}

/// Invoke an `unsafe` method. Like [unsafe_fn], but
/// - This accepts a receiver `&self`, `&mut self` and `self`. TODO Box/Rc/Arc, dyn?
/// - This treats `self` as if it were evaluated **outside** the `unsafe {...}` block.
/// - $fn can **NOT** be an expression or a qualified path (which doesn't work in standard methods
///   calls anyways), but only an identifier.
/// ```compile_fail
#[doc = include_str!("../violations_coverage/unsafe_method/some_args/arg.rs")]
/// ```
/// ```compile_fail
#[doc = include_str!("../violations_coverage/unsafe_method/some_args/self.rs")]
/// ```
#[macro_export]
macro_rules! unsafe_method {
    ($self:expr, $fn:ident $(, $arg:expr)* ) => {
        // Enclosed in a block, so that the result can be used as a value in an outer expression
        // without upsetting operator precedence.
        {
            if false {
                if false {
                    // This block makes an instance/owned value of the same type as $self. The
                    // purpose is then to invoke the method inside unsafe {...}, BUT without
                    // evaluating the given $self expression inside that unsafe {...} block, so that
                    // we isolate/catch any unsafe code in $self.
                    //
                    // We **cannot** move/take/assign $self by value, in case it's a non-Copy
                    // **static** variable.
                    let rref = &( $self );
                    let mref = ::prudent::shared_to_mut(rref);
                    let mut owned_receiver = ::core::mem::replace(mref, unsafe{ ::core::mem::zeroed() });
                    let _ = unsafe { owned_receiver. $fn( $( $arg ),* ) };
                } else {
                    $( let _ = $arg; )*
                }
                unreachable!()
            } else {
                #[allow(unsafe_code)]
                //@TODO: for unsafe_fn, too:
                //
                // If $self or any $arg include `unsafe {...}`, that would trigger "unused_unsafe".
                //
                // Unfortunately, because of this, we can't detect code where unsafe_fn! or
                // unsafe_method! is not needed at all. For example, if a function/method use to be
                // `unsafe`, and it stopped being so.
                #[allow(unused_unsafe)]
                unsafe { $self. $fn ( $( $arg ),* ) }
            }
        }
    };
    (#allow_unsafe $self:expr, $fn:ident $(, $arg:expr)* ) => {
    }
}

